function e($v):string{return htmlspecialchars((string)($v??''),ENT_QUOTES,'UTF-8');}
function billingPermission(mysqli $conn,string $action):bool{
    if(($_SESSION['user_type']??'')==='Platform Admin')return true;
    $map=['open'=>'can_open','create'=>'can_create','value'=>'can_view_value'];$field=$map[$action]??'';if($field==='')return false;
    foreach(['perm.billing.create','perm.billing'] as $code){if(isset($_SESSION['permissions'][$code][$field]))return(int)$_SESSION['permissions'][$code][$field]===1;}
    $businessId=(int)($_SESSION['business_id']??0);$roleId=(int)($_SESSION['role_id']??0);if($businessId<=0||$roleId<=0)return false;
    $sql="SELECT rp.`{$field}` FROM role_permissions rp INNER JOIN permissions p ON p.id=rp.permission_id WHERE rp.business_id=? AND rp.role_id=? AND p.is_active=1 AND p.permission_code IN ('perm.billing.create','perm.billing') ORDER BY FIELD(p.permission_code,'perm.billing.create','perm.billing') LIMIT 1";
    $stmt=$conn->prepare($sql);if(!$stmt)return false;$stmt->bind_param('ii',$businessId,$roleId);$stmt->execute();$row=$stmt->get_result()->fetch_assoc();$stmt->close();return(int)($row[$field]??0)===1;
}
if(!billingPermission($conn,'open')&&!billingPermission($conn,'create')){http_response_code(403);die('You do not have permission to create bills.');}
$businessId=(int)($_SESSION['business_id']??0);$branchId=(int)($_SESSION['branch_id']??($_SESSION['default_branch_id']??0));
if($businessId<=0||$branchId<=0)die('A valid business and branch must be selected.');
if(empty($_SESSION['billing_csrf']))$_SESSION['billing_csrf']=bin2hex(random_bytes(32));$csrfToken=(string)$_SESSION['billing_csrf'];
$theme=['primary_color'=>'#d89416','primary_dark_color'=>'#b86a0b','primary_soft_color'=>'#fff6e5','page_background'=>'#f4f3f0','card_background'=>'#fff','text_color'=>'#171717','muted_text_color'=>'#7d8794','border_color'=>'#e8e8e8','font_family'=>'Inter','heading_font_family'=>'Playfair Display','border_radius_px'=>12,'sidebar_width_px'=>230,'sidebar_gradient_1'=>'#171c21','sidebar_gradient_2'=>'#20272d','sidebar_gradient_3'=>'#101419'];
$stmt=$conn->prepare('SELECT * FROM business_theme_settings WHERE business_id=? LIMIT 1');if($stmt){$stmt->bind_param('i',$businessId);$stmt->execute();$x=$stmt->get_result()->fetch_assoc()?:[];$stmt->close();foreach($theme as $k=>$v)if(isset($x[$k])&&$x[$k]!=='')$theme[$k]=$x[$k];}
$customers=[];$stmt=$conn->prepare("SELECT id,customer_code,customer_name,mobile,gstin FROM customers WHERE business_id=? AND is_active=1 AND customer_type IN ('Billing','All') ORDER BY customer_name");if($stmt){$stmt->bind_param('i',$businessId);$stmt->execute();$r=$stmt->get_result();while($x=$r->fetch_assoc())$customers[]=$x;$stmt->close();}
$products=[];$stmt=$conn->prepare("SELECT p.id,p.product_code,p.barcode,p.product_name,p.hsn_code,p.gross_weight,p.stone_weight,p.net_weight,p.wastage_percent,p.making_charge_type,p.making_charge,p.purchase_rate,p.sale_rate,p.tax_percent,p.track_stock,COALESCE(ps.quantity,0) stock_qty FROM products p LEFT JOIN product_stock ps ON ps.product_id=p.id AND ps.business_id=p.business_id AND ps.branch_id=? WHERE p.business_id=? AND p.is_active=1 ORDER BY p.product_name");if($stmt){$stmt->bind_param('ii',$branchId,$businessId);$stmt->execute();$r=$stmt->get_result();while($x=$r->fetch_assoc())$products[]=$x;$stmt->close();}
$paymentMethods=[];$stmt=$conn->prepare('SELECT id,method_name FROM payment_methods WHERE business_id=? AND is_active=1 ORDER BY method_name');if($stmt){$stmt->bind_param('i',$businessId);$stmt->execute();$r=$stmt->get_result();while($x=$r->fetch_assoc())$paymentMethods[]=$x;$stmt->close();}
$invoiceSetting=null;$stmt=$conn->prepare("SELECT * FROM invoice_settings WHERE business_id=? AND (branch_id=? OR branch_id IS NULL) AND document_type='Invoice' AND is_active=1 ORDER BY (branch_id=? ) DESC,is_default DESC,id DESC LIMIT 1");if($stmt){$stmt->bind_param('iii',$businessId,$branchId,$branchId);$stmt->execute();$invoiceSetting=$stmt->get_result()->fetch_assoc();$stmt->close();}
function previewInvoiceNo(?array $s):string{if(!$s)return 'INV'.date('ymd').'0001';$prefix=$s['prefix']??'INV';$split=$s['splitter_symbol']??'/';$digits=max(1,(int)($s['sequence_digits']??3));$start=max(1,(int)($s['sequence_start']??1));$fy=(int)date('n')>=4?date('y').'-'.date('y',strtotime('+1 year')):date('y',strtotime('-1 year')).'-'.date('y');$map=['{PREFIX}'=>$prefix,'{SPLITTER}'=>$split,'{FY_SHORT}'=>$fy,'{FY_2DIGIT}'=>str_replace('-','',$fy),'{YYYY}'=>date('Y'),'{MM}'=>date('m'),'{DD}'=>date('d'),'{SEQ}'=>str_pad((string)$start,$digits,'0',STR_PAD_LEFT)];return strtr($s['format_template']??'{PREFIX}{SPLITTER}{FY_SHORT}{SPLITTER}{SEQ}',$map);}
$pageTitle='Billing';$businessName=(string)($_SESSION['business_name']??'Jewellery ERP');$defaultBillNo=previewInvoiceNo($invoiceSetting);
?>
<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title><?=e($businessName)?> - Billing</title><?php include('includes/links.php'); ?><style>
:root{--primary:<?=e($theme['primary_color'])?>;--primary-dark:<?=e($theme['primary_dark_color'])?>;--primary-soft:<?=e($theme['primary_soft_color'])?>;--page-bg:<?=e($theme['page_background'])?>;--card-bg:<?=e($theme['card_background'])?>;--text:<?=e($theme['text_color'])?>;--muted:<?=e($theme['muted_text_color'])?>;--line:<?=e($theme['border_color'])?>;--radius:<?=(int)$theme['border_radius_px']?>px;--sidebar-width:<?=(int)$theme['sidebar_width_px']?>px;--sidebar-gradient-1:<?=e($theme['sidebar_gradient_1'])?>;--sidebar-gradient-2:<?=e($theme['sidebar_gradient_2'])?>;--sidebar-gradient-3:<?=e($theme['sidebar_gradient_3'])?>}body{background:var(--page-bg);color:var(--text);font-family:<?=json_encode($theme['font_family'])?>,sans-serif}.sidebar{background:linear-gradient(180deg,var(--sidebar-gradient-1),var(--sidebar-gradient-2),var(--sidebar-gradient-3))!important}.bill-card{background:var(--card-bg);border:1px solid var(--line);border-radius:var(--radius);overflow:hidden;margin-bottom:12px}.bill-head{padding:14px 16px;border-bottom:1px solid var(--line);display:flex;align-items:center;justify-content:space-between}.bill-title{font:700 20px <?=json_encode($theme['heading_font_family'])?>,serif}.section-title{font-size:11px;font-weight:800;text-transform:uppercase;letter-spacing:.06em;color:var(--primary-dark)}.bill-body{padding:16px}.field-label{font-size:10px;font-weight:700;margin-bottom:5px}.form-control,.form-select{font-size:11px;min-height:38px;border-color:var(--line);border-radius:9px;background:var(--card-bg);color:var(--text)}.btn-theme{background:linear-gradient(135deg,var(--primary),var(--primary-dark));border:0;color:#fff;font-size:11px;font-weight:700;border-radius:9px;padding:9px 15px}.table{font-size:10px}.table th{font-size:9px;text-transform:uppercase;color:var(--muted);background:color-mix(in srgb,var(--muted) 6%,transparent);white-space:nowrap}.table td,.table th{border-color:var(--line);vertical-align:middle}.new-customer-panel{display:none;margin-top:12px;padding:13px;border:1px dashed var(--primary);border-radius:10px;background:var(--primary-soft)}.new-customer-panel.show{display:block}.summary-card{position:sticky;top:76px}.summary-row{display:flex;justify-content:space-between;padding:7px 0;border-bottom:1px dashed var(--line);font-size:11px}.summary-total{font-size:16px;font-weight:800;color:var(--primary-dark)}.theme-toast{position:fixed;right:18px;top:78px;z-index:20000;padding:11px 14px;border-radius:10px;color:#fff;font-size:11px;font-weight:600;opacity:0;transform:translateY(-10px);transition:.22s}.theme-toast.show{opacity:1;transform:none}.theme-toast-success{background:#168449}.theme-toast-error{background:#c0392b}body.dark-mode,body[data-theme=dark]{--page-bg:#0f151b;--card-bg:#182129;--text:#f3f6f8;--muted:#9aa7b3;--line:#2c3944}@media(max-width:991px){.summary-card{position:static}}
</style></head><body><?php include('includes/sidebar.php'); ?><main class="app-main"><?php include('includes/nav.php'); ?><div class="content-wrap"><form id="billingForm" autocomplete="off"><input type="hidden" name="csrf_token" value="<?=e($csrfToken)?>"><input type="hidden" name="action" value="save"><div class="bill-card"><div class="bill-head"><div><div class="bill-title">Create Bill</div><div class="small text-muted">Create a jewellery sales invoice.</div></div><a href="sales-list.php" class="btn btn-light btn-sm"><i class="fa-solid fa-arrow-left me-2"></i>Back</a></div></div><div class="row g-3"><div class="col-xl-9"><div class="bill-card"><div class="bill-head"><div class="section-title">Bill Details</div></div><div class="bill-body"><div class="row g-3"><div class="col-md-3"><label class="field-label">Bill No</label><input class="form-control" value="<?=e($defaultBillNo)?>" readonly></div><div class="col-md-3"><label class="field-label">Bill Date *</label><input type="date" name="invoice_date" class="form-control" value="<?=date('Y-m-d')?>" required></div><div class="col-md-3"><label class="field-label">Bill Time *</label><input type="time" name="invoice_time" class="form-control" value="<?=date('H:i')?>" required></div><div class="col-md-3"><label class="field-label">Bill Type</label><select name="bill_type" class="form-select"><option>Retail</option><option>GST</option><option>Estimate</option><option>Exchange</option></select></div><div class="col-md-6"><label class="field-label">Customer *</label><select name="customer_id" id="customerId" class="form-select" required><option value="">Select customer</option><?php foreach($customers as $c):?><option value="<?=(int)$c['id']?>"><?=e($c['customer_name'].(!empty($c['customer_code'])?' - '.$c['customer_code']:'').(!empty($c['mobile'])?' - '.$c['mobile']:''))?></option><?php endforeach?><option value="new">+ Add New Customer</option></select><div class="new-customer-panel" id="newCustomerPanel"><div class="row g-2"><div class="col-md-4"><label class="field-label">Customer Name *</label><input name="new_customer_name" id="newCustomerName" class="form-control" placeholder="New customer name"></div><div class="col-md-4"><label class="field-label">Mobile</label><input name="new_customer_mobile" class="form-control" placeholder="Mobile number" maxlength="20"></div><div class="col-md-4"><label class="field-label">GSTIN</label><input name="new_customer_gstin" class="form-control text-uppercase" placeholder="GSTIN" maxlength="30"></div></div><div class="small text-muted mt-2">The new customer will be created automatically when this bill is saved.</div></div></div><div class="col-md-6"><label class="field-label">Notes</label><input name="notes" class="form-control" placeholder="Bill notes"></div></div></div></div><div class="bill-card"><div class="bill-head"><div class="section-title">Bill Items</div><button type="button" class="btn btn-theme btn-sm" id="addItem"><i class="fa-solid fa-plus me-1"></i>Add Item</button></div><div class="table-responsive"><table class="table mb-0"><thead><tr><th style="min-width:230px">Product</th><th>Qty</th><th>Rate</th><th>Making</th><th>Stone</th><th>Other</th><th>Discount</th><th>Total</th><th></th></tr></thead><tbody id="itemsBody"></tbody></table></div></div><div class="bill-card"><div class="bill-head"><div class="section-title">Split Payments</div><button type="button" class="btn btn-theme btn-sm" id="addPayment"><i class="fa-solid fa-plus me-1"></i>Add Payment</button></div><div class="table-responsive"><table class="table mb-0"><thead><tr><th>Method</th><th>Amount</th><th>Reference</th><th></th></tr></thead><tbody id="paymentsBody"></tbody></table></div><div class="bill-body text-end"><strong>Split Total: ₹<span id="splitTotal">0.00</span></strong></div></div></div><div class="col-xl-3"><div class="bill-card summary-card"><div class="bill-head"><div class="section-title">Bill Summary</div></div><div class="bill-body"><label class="field-label">Overall Discount</label><input type="number" min="0" step="0.01" name="overall_discount" id="overallDiscount" class="form-control mb-2" value="0"><label class="field-label">Round Off</label><input type="number" step="0.01" name="round_off" id="roundOff" class="form-control mb-2" value="0"><label class="field-label">Paid Amount</label><input type="number" min="0" step="0.01" name="paid_amount" id="paidAmount" class="form-control mb-3" value="0"><div class="summary-row"><span>Subtotal</span><strong>₹<span id="sumSubtotal">0.00</span></strong></div><div class="summary-row"><span>Discount</span><strong>₹<span id="sumDiscount">0.00</span></strong></div><div class="summary-row"><span>Taxable</span><strong>₹<span id="sumTaxable">0.00</span></strong></div><div class="summary-row"><span>CGST</span><strong>₹<span id="sumCgst">0.00</span></strong></div><div class="summary-row"><span>SGST</span><strong>₹<span id="sumSgst">0.00</span></strong></div><div class="summary-row"><span>Grand Total</span><strong class="summary-total">₹<span id="sumGrand">0.00</span></strong></div><div class="summary-row"><span>Balance</span><strong>₹<span id="sumBalance">0.00</span></strong></div><button class="btn btn-theme w-100 mt-3" id="saveBtn"><i class="fa-solid fa-floppy-disk me-2"></i>Save Bill</button></div></div></div></div></form><?php include('includes/footer.php'); ?></div></main><?php include('includes/script.php'); ?><script src="assets/js/script.js"></script><script>
(()=>{'use strict';const products=<?=json_encode($products,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES)?>,payments=<?=json_encode($paymentMethods,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES)?>;const form=document.getElementById('billingForm'),items=document.getElementById('itemsBody'),pays=document.getElementById('paymentsBody'),customer=document.getElementById('customerId'),panel=document.getElementById('newCustomerPanel');function esc(v){return String(v??'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#039;','"':'&quot;'}[c]))}function toast(t,m){const x=document.createElement('div');x.className='theme-toast theme-toast-'+t;x.textContent=m;document.body.appendChild(x);requestAnimationFrame(()=>x.classList.add('show'));setTimeout(()=>{x.classList.remove('show');setTimeout(()=>x.remove(),250)},3200)}function productOptions(){return '<option value="">Select product</option>'+products.map(p=>`<option value="${p.id}" data-p='${esc(JSON.stringify(p))}'>${esc(p.product_name+' - '+p.product_code+' (Stock: '+Number(p.stock_qty).toFixed(3)+')')}</option>`).join('')}function paymentOptions(){return '<option value="">Select method</option>'+payments.map(p=>`<option value="${p.id}">${esc(p.method_name)}</option>`).join('')}function addItem(){items.insertAdjacentHTML('beforeend',`<tr class="item-row"><td><select name="product_id[]" class="form-select product-select">${productOptions()}</select><small class="text-muted stock-info"></small></td><td><input name="quantity[]" type="number" min="0.001" step="0.001" value="1" class="form-control qty"></td><td><input name="metal_rate[]" type="number" min="0" step="0.01" value="0" class="form-control rate"></td><td><input name="making_charge[]" type="number" min="0" step="0.01" value="0" class="form-control making"></td><td><input name="stone_amount[]" type="number" min="0" step="0.01" value="0" class="form-control stone"></td><td><input name="other_charge[]" type="number" min="0" step="0.01" value="0" class="form-control other"></td><td><input name="item_discount[]" type="number" min="0" step="0.01" value="0" class="form-control discount"></td><td><input class="form-control line-total" value="0.00" readonly></td><td><button type="button" class="btn btn-sm btn-outline-danger remove-row"><i class="fa-solid fa-xmark"></i></button></td></tr>`)}function addPay(){pays.insertAdjacentHTML('beforeend',`<tr class="payment-row"><td><select name="payment_method_id[]" class="form-select">${paymentOptions()}</select></td><td><input name="payment_amount[]" type="number" min="0" step="0.01" value="0" class="form-control pay-amount"></td><td><input name="payment_reference[]" class="form-control" placeholder="UPI / Txn / Ref"></td><td><button type="button" class="btn btn-sm btn-outline-danger remove-row"><i class="fa-solid fa-xmark"></i></button></td></tr>`)}function calc(){let subtotal=0,itemDisc=0,taxable=0,cgst=0,sgst=0;items.querySelectorAll('.item-row').forEach(r=>{const sel=r.querySelector('.product-select'),p=products.find(x=>String(x.id)===sel.value),q=+r.querySelector('.qty').value||0,rate=+r.querySelector('.rate').value||0,m=+r.querySelector('.making').value||0,s=+r.querySelector('.stone').value||0,o=+r.querySelector('.other').value||0,d=+r.querySelector('.discount').value||0;if(!p){r.querySelector('.line-total').value='0.00';return}const nw=(+p.net_weight||0)*q,metal=nw>0?nw*rate:q*rate,waste=metal*(+p.wastage_percent||0)/100,rowSub=metal+m+waste+s+o,rowTax=Math.max(0,rowSub-d),tax=rowTax*(+p.tax_percent||0)/100,total=rowTax+tax;r.querySelector('.line-total').value=total.toFixed(2);subtotal+=rowSub;itemDisc+=d;taxable+=rowTax;cgst+=tax/2;sgst+=tax/2});const overall=+document.getElementById('overallDiscount').value||0,round=+document.getElementById('roundOff').value||0;taxable=Math.max(0,taxable-overall);const grand=taxable+cgst+sgst+round,paid=Math.min(+document.getElementById('paidAmount').value||0,grand);document.getElementById('sumSubtotal').textContent=subtotal.toFixed(2);document.getElementById('sumDiscount').textContent=(itemDisc+overall).toFixed(2);document.getElementById('sumTaxable').textContent=taxable.toFixed(2);document.getElementById('sumCgst').textContent=cgst.toFixed(2);document.getElementById('sumSgst').textContent=sgst.toFixed(2);document.getElementById('sumGrand').textContent=grand.toFixed(2);document.getElementById('sumBalance').textContent=Math.max(0,grand-paid).toFixed(2);let split=0;pays.querySelectorAll('.pay-amount').forEach(x=>split+=+x.value||0);document.getElementById('splitTotal').textContent=split.toFixed(2)}customer.addEventListener('change',()=>{const on=customer.value==='new';panel.classList.toggle('show',on);document.getElementById('newCustomerName').required=on});document.getElementById('addItem').onclick=addItem;document.getElementById('addPayment').onclick=addPay;document.addEventListener('click',e=>{const b=e.target.closest('.remove-row');if(b){b.closest('tr').remove();calc()}});document.addEventListener('change',e=>{if(e.target.matches('.product-select')){const r=e.target.closest('tr'),p=products.find(x=>String(x.id)===e.target.value);if(p){r.querySelector('.rate').value=p.sale_rate||0;r.querySelector('.making').value=p.making_charge||0;r.querySelector('.stock-info').textContent='Available: '+Number(p.stock_qty||0).toFixed(3)}calc()}});document.addEventListener('input',e=>{if(e.target.closest('#billingForm'))calc()});form.addEventListener('submit',async e=>{e.preventDefault();if(customer.value===''){toast('error','Please select a customer.');return}if(customer.value==='new'&&!document.getElementById('newCustomerName').value.trim()){toast('error','Enter the new customer name.');return}const b=document.getElementById('saveBtn'),old=b.innerHTML;b.disabled=true;b.innerHTML='<i class="fa-solid fa-spinner fa-spin me-2"></i>Saving...';try{const res=await fetch('api/billing.php',{method:'POST',body:new FormData(form),credentials:'same-origin',headers:{'X-Requested-With':'XMLHttpRequest','Accept':'application/json'}});const raw=await res.text();let data;try{data=JSON.parse(raw)}catch(parseError){const preview=raw.replace(/<[^>]*>/g,' ').replace(/\s+/g,' ').trim().slice(0,500);throw new Error('API did not return JSON. HTTP '+res.status+'. '+(preview||'Check that api/billing.php exists and PHP errors are not being printed.'))}if(!res.ok||!data.success)throw new Error(data.message||'Unable to save bill.');toast('success',data.message);setTimeout(()=>location.href='sales-list.php?msg=created&sale_id='+encodeURIComponent(data.sale_id),700)}catch(err){toast('error',err.message)}finally{b.disabled=false;b.innerHTML=old}});addItem();addPay();calc()})();
</script></body></html>
